import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useApp } from '../context/AppContext';
import { ShoppingCart, Trash2, Plus, Minus, ArrowLeft, CheckCircle } from 'lucide-react';

export default function CartPage() {
  const { cart, removeFromCart, addToCart, clearCart, cartTotal, createOrder } = useApp();
  const [notes, setNotes] = useState('');
  const [success, setSuccess] = useState(null);
  const navigate = useNavigate();

  const updateQty = (item, delta) => {
    if (item.qty + delta <= 0) return removeFromCart(item.productId);
    addToCart({ id: item.productId, name: item.name, price: item.price, image: item.image }, delta);
  };

  const confirm = () => {
    const order = createOrder(notes);
    setSuccess(order);
  };

  if (success) {
    return (
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', minHeight: '60vh', textAlign: 'center' }}>
        <div style={{ fontSize: '4rem', marginBottom: 16 }}>🎉</div>
        <div style={{ color: 'var(--success)', marginBottom: 12 }}><CheckCircle size={40} /></div>
        <h2 style={{ fontSize: '1.6rem', marginBottom: 8 }}>¡Pedido confirmado!</h2>
        <p style={{ color: 'var(--gray-400)', marginBottom: 6 }}>Tu pedido fue registrado exitosamente</p>
        <p style={{ color: 'var(--pink-500)', fontWeight: 700, fontSize: '1.1rem', marginBottom: 28 }}>ID: {success.id}</p>
        <div style={{ display: 'flex', gap: 12 }}>
          <Link to="/mis-pedidos" className="btn btn-primary">Ver mis pedidos</Link>
          <Link to="/catalogo" className="btn btn-secondary">Seguir comprando</Link>
        </div>
      </div>
    );
  }

  if (cart.length === 0) {
    return (
      <div>
        <h1 style={{ marginBottom: 24 }}>Mi Carrito</h1>
        <div className="empty-state" style={{ padding: '80px 20px' }}>
          <span style={{ fontSize: '3rem' }}>🛒</span>
          <p>Tu carrito está vacío</p>
          <Link to="/catalogo" className="btn btn-primary" style={{ marginTop: 12 }}>Ver catálogo</Link>
        </div>
      </div>
    );
  }

  return (
    <div>
      <div className="page-header">
        <div><h1>Mi Carrito</h1><p>{cart.length} productos</p></div>
        <Link to="/catalogo" className="btn btn-secondary"><ArrowLeft size={15} /> Seguir comprando</Link>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 340px', gap: 24 }}>
        <div className="card">
          {cart.map(item => (
            <div key={item.productId} style={{ display: 'flex', alignItems: 'center', gap: 14, padding: '18px 22px', borderBottom: '1px solid var(--gray-100)' }}>
              <span style={{ fontSize: '2.2rem' }}>{item.image}</span>
              <div style={{ flex: 1 }}>
                <p style={{ fontWeight: 600, fontSize: '0.95rem' }}>{item.name}</p>
                <p style={{ color: 'var(--pink-500)', fontWeight: 700 }}>${item.price.toFixed(2)}</p>
              </div>
              <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                <button onClick={() => updateQty(item, -1)} className="btn btn-secondary btn-sm" style={{ width: 30, height: 30, padding: 0, justifyContent: 'center' }}><Minus size={13} /></button>
                <span style={{ fontWeight: 700, minWidth: 24, textAlign: 'center' }}>{item.qty}</span>
                <button onClick={() => updateQty(item, 1)} className="btn btn-secondary btn-sm" style={{ width: 30, height: 30, padding: 0, justifyContent: 'center' }}><Plus size={13} /></button>
              </div>
              <span style={{ fontWeight: 700, minWidth: 60, textAlign: 'right' }}>${(item.price * item.qty).toFixed(2)}</span>
              <button onClick={() => removeFromCart(item.productId)} className="btn btn-danger btn-sm" style={{ padding: '6px 8px' }}><Trash2 size={14} /></button>
            </div>
          ))}
        </div>

        <div>
          <div className="card" style={{ padding: '24px' }}>
            <h3 style={{ fontSize: '1.1rem', marginBottom: 18 }}>Resumen del pedido</h3>

            {cart.map(item => (
              <div key={item.productId} style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 8, fontSize: '0.88rem', color: 'var(--gray-500)' }}>
                <span>{item.name} x{item.qty}</span>
                <span>${(item.price * item.qty).toFixed(2)}</span>
              </div>
            ))}

            <div style={{ borderTop: '2px solid var(--gray-100)', marginTop: 14, paddingTop: 14, display: 'flex', justifyContent: 'space-between', fontWeight: 700, fontSize: '1.1rem' }}>
              <span>Total</span>
              <span style={{ color: 'var(--pink-500)' }}>${cartTotal.toFixed(2)}</span>
            </div>

            <div className="form-group" style={{ marginTop: 18 }}>
              <label>Notas del pedido</label>
              <textarea value={notes} onChange={e => setNotes(e.target.value)} rows={3} placeholder="Ej: Sin nueces, para cumpleaños..." style={{ resize: 'none' }} />
            </div>

            <button onClick={confirm} className="btn btn-primary btn-lg" style={{ width: '100%', justifyContent: 'center' }}>
              <ShoppingCart size={17} /> Confirmar pedido
            </button>
            <button onClick={clearCart} className="btn btn-danger" style={{ width: '100%', justifyContent: 'center', marginTop: 8 }}>
              Vaciar carrito
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
